import { useState } from "react";

const THEMES = {
  blue: {
    text: "text-blue-200",
    rangeInput: "w-14 h-2 cursor-pointer accent-blue-500",
    send: "bg-blue-600 px-3 py-1 rounded",
  },
  orange: {
    text: "text-orange-200",
    rangeInput: "w-14 h-2 cursor-pointer accent-orange-500",
    send: "bg-orange-600 px-3 py-1 rounded",
  },
};

export default function ClueInput({ onSend, disabled }) {
  const [state, setState] = useState({
    blue: { word: "", count: 1 },
    orange: { word: "", count: 1 },
  });

  // ✅ WITH prev (safe & recommended)
  const handleChange = (team, field, value) => {
    setState((prev) => ({
      ...prev,
      [team]: {
        ...prev[team],
        [field]: value,
      },
    }));
  };

  const handleSend = (team) => {
    if (!state[team].word.trim() || disabled) return;

    onSend({
      team,
      clue: state[team].word,
      count: state[team].count,
    });

    setState((prev) => ({
      ...prev,
      [team]: { word: "", count: 1 },
    }));
  };

  const renderTeam = (team) => {
    const t = THEMES[team];
    const data = state[team];

    return (
      <div className="flex items-center gap-3 bg-gray-900 p-3 rounded-xl shadow-lg">
        <input
          type="text"
          value={data.word}
          onChange={(e) => handleChange(team, "word", e.target.value)}
          disabled={disabled}
          className={t.text}
          placeholder={`${team} clue`}
        />

        <input
          type="range"
          min={1}
          max={9}
          value={data.count}
          onChange={(e) =>
            handleChange(team, "count", Number(e.target.value))
          }
          disabled={disabled}
          className={t.rangeInput}
        />

        <output>{data.count}</output>

        <button
          onClick={() => handleSend(team)}
          disabled={disabled}
          className={t.send}
        >
          Send
        </button>
      </div>
    );
  };

  return (
    <>
      {renderTeam("blue")}
      {renderTeam("orange")}
    </>
  );
}
